class Solution:
    def minDifference(self, nums, queries):
        """
        :type nums: List[int]
        :type queries: List[List[int]]
        :rtype: List[int]
        """
        # Prefix sum for each number 1-100
        n = len(nums)
        prefix = [[0] * 101 for _ in range(n + 1)]

        for i in range(n):
            for j in range(101):
                prefix[i+1][j] = prefix[i][j]
            prefix[i+1][nums[i]] += 1

        result = []

        for left, right in queries:
            # Get count of each number in range [left, right]
            present = []
            for num in range(1, 101):
                if prefix[right + 1][num] - prefix[left][num] > 0:
                    present.append(num)

            if len(present) < 2:
                result.append(-1)
            else:
                min_diff = float('inf')
                for i in range(len(present) - 1):
                    min_diff = min(min_diff, present[i+1] - present[i])
                result.append(min_diff)

        return result
